fun eulerPath(arr: IntArray): Int {
    val n = arr[0]; val m = arr[1]
    if (n == 0) return 1
    val adj = Array(n) { mutableListOf<Int>() }
    val degree = IntArray(n)
    for (i in 0 until m) {
        val u = arr[2+2*i]; val v = arr[3+2*i]
        adj[u].add(v); adj[v].add(u)
        degree[u]++; degree[v]++
    }
    for (d in degree) if (d % 2 != 0) return 0
    var start = -1
    for (i in 0 until n) if (degree[i] > 0) { start = i; break }
    if (start == -1) return 1
    val visited = BooleanArray(n)
    val stack = ArrayDeque<Int>()
    stack.addLast(start); visited[start] = true
    while (stack.isNotEmpty()) {
        val v = stack.removeLast()
        for (u in adj[v]) if (!visited[u]) { visited[u] = true; stack.addLast(u) }
    }
    for (i in 0 until n) if (degree[i] > 0 && !visited[i]) return 0
    return 1
}

def euler_path(arr: list[int]) -> int:
    n = arr[0]
    m = arr[1]
    if n == 0:
        return 1
    adj = [[] for _ in range(n)]
    degree = [0] * n
    for i in range(m):
        u, v = arr[2 + 2 * i], arr[3 + 2 * i]
        adj[u].append(v)
        adj[v].append(u)
        degree[u] += 1
        degree[v] += 1

    # Check all degrees are even
    for d in degree:
        if d % 2 != 0:
            return 0

    # Check connectivity of non-zero degree vertices
    start = -1
    for i in range(n):
        if degree[i] > 0:
            start = i
            break
    if start == -1:
        return 1  # no edges

    visited = [False] * n
    stack = [start]
    visited[start] = True
    while stack:
        v = stack.pop()
        for u in adj[v]:
            if not visited[u]:
                visited[u] = True
                stack.append(u)

    for i in range(n):
        if degree[i] > 0 and not visited[i]:
            return 0

    return 1

pub fn euler_path(arr: &[i32]) -> i32 {
    let n = arr[0] as usize;
    let m = arr[1] as usize;
    if n == 0 { return 1; }
    let mut adj = vec![vec![]; n];
    let mut degree = vec![0usize; n];
    for i in 0..m {
        let u = arr[2+2*i] as usize;
        let v = arr[3+2*i] as usize;
        adj[u].push(v); adj[v].push(u);
        degree[u] += 1; degree[v] += 1;
    }
    for &d in &degree { if d % 2 != 0 { return 0; } }
    let mut start = None;
    for i in 0..n { if degree[i] > 0 { start = Some(i); break; } }
    let start = match start { Some(s) => s, None => return 1 };
    let mut visited = vec![false; n];
    let mut stack = vec![start];
    visited[start] = true;
    while let Some(v) = stack.pop() {
        for &u in &adj[v] { if !visited[u] { visited[u] = true; stack.push(u); } }
    }
    for i in 0..n { if degree[i] > 0 && !visited[i] { return 0; } }
    1
}

object EulerPath {
  def eulerPath(arr: Array[Int]): Int = {
    val n = arr(0); val m = arr(1)
    if (n == 0) return 1
    val adj = Array.fill(n)(scala.collection.mutable.ArrayBuffer[Int]())
    val degree = new Array[Int](n)
    for (i <- 0 until m) {
      val u = arr(2+2*i); val v = arr(3+2*i)
      adj(u) += v; adj(v) += u
      degree(u) += 1; degree(v) += 1
    }
    for (d <- degree) if (d % 2 != 0) return 0
    var start = -1
    for (i <- 0 until n) if (degree(i) > 0 && start == -1) start = i
    if (start == -1) return 1
    val visited = new Array[Boolean](n)
    val stack = scala.collection.mutable.Stack[Int]()
    stack.push(start); visited(start) = true
    while (stack.nonEmpty) {
      val v = stack.pop()
      for (u <- adj(v)) if (!visited(u)) { visited(u) = true; stack.push(u) }
    }
    for (i <- 0 until n) if (degree(i) > 0 && !visited(i)) return 0
    1
  }
}

func eulerPath(_ arr: [Int]) -> Int {
    let n = arr[0], m = arr[1]
    if n == 0 { return 1 }
    var adj = [[Int]](repeating: [], count: n)
    var degree = [Int](repeating: 0, count: n)
    for i in 0..<m {
        let u = arr[2+2*i], v = arr[3+2*i]
        adj[u].append(v); adj[v].append(u)
        degree[u] += 1; degree[v] += 1
    }
    for d in degree { if d % 2 != 0 { return 0 } }
    var start = -1
    for i in 0..<n { if degree[i] > 0 { start = i; break } }
    if start == -1 { return 1 }
    var visited = [Bool](repeating: false, count: n)
    var stack = [start]
    visited[start] = true
    while !stack.isEmpty {
        let v = stack.removeLast()
        for u in adj[v] { if !visited[u] { visited[u] = true; stack.append(u) } }
    }
    for i in 0..<n { if degree[i] > 0 && !visited[i] { return 0 } }
    return 1
}

export function eulerPath(arr: number[]): number {
    const n = arr[0], m = arr[1];
    if (n === 0) return 1;
    const adj: number[][] = Array.from({ length: n }, () => []);
    const degree = new Array(n).fill(0);
    for (let i = 0; i < m; i++) {
        const u = arr[2+2*i], v = arr[3+2*i];
        adj[u].push(v); adj[v].push(u);
        degree[u]++; degree[v]++;
    }
    for (const d of degree) if (d % 2 !== 0) return 0;
    let start = -1;
    for (let i = 0; i < n; i++) if (degree[i] > 0) { start = i; break; }
    if (start === -1) return 1;
    const visited = new Array(n).fill(false);
    const stack = [start];
    visited[start] = true;
    while (stack.length > 0) {
        const v = stack.pop()!;
        for (const u of adj[v]) if (!visited[u]) { visited[u] = true; stack.push(u); }
    }
    for (let i = 0; i < n; i++) if (degree[i] > 0 && !visited[i]) return 0;
    return 1;
}
